16. // RegisterUrlRoutes registers all URL management endpoints on the given Huma API.
17. func RegisterUrlRoutes(api huma.API, h *handlers.UrlHandler) {
18. 	huma.Register(api, huma.Operation{
19. 		OperationID: "list-user-urls",
20. 		Method:      http.MethodGet,
21. 		Path:        "/user/urls",
22. 		Summary:     "List authenticated user's shortened URLs",
23. 	}, func(ctx context.Context, input *viewmodels.ListUrlsInput) (*viewmodels.ListUrlsResponse, error) {
24. 		claims := GetJWTClaimsFromContext(ctx)
25. 		if claims == nil {
26. 			return nil, huma.NewError(http.StatusUnauthorized, "unauthorized")
27. 		}
28. 
29. 		pageSize := resolvePageSize(input.PageSize)
30. 
31. 		urls, total, err := h.ListUrls(ctx, claims.UserID, input.Page, pageSize)
32. 		if err != nil {
33. 			return nil, MapError(err)
34. 		}
35. 
36. 		return &viewmodels.ListUrlsResponse{
37. 			Body: webmappers.ListUrlsToResponse(urls, total, input.Page, pageSize),
38. 		}, nil
39. 	})
40. 
41. 	huma.Register(api, huma.Operation{
42. 		OperationID:   "create-shortened-url",
43. 		Method:        http.MethodPost,
44. 		Path:          "/user/urls",
45. 		Summary:       "Create a new shortened URL",
46. 		DefaultStatus: http.StatusCreated,
47. 	}, func(ctx context.Context, input *viewmodels.CreateUrlInput) (*viewmodels.CreateUrlResponse, error) {
48. 		claims := GetJWTClaimsFromContext(ctx)
49. 		if claims == nil {
50. 			return nil, huma.NewError(http.StatusUnauthorized, "unauthorized")
51. 		}
52. 
53. 		created, err := h.CreateUrl(ctx, claims.UserID, input.Body.LongUrl, input.Body.Shortcode, input.Body.ExpiresAt)
54. 		if err != nil {
55. 			return nil, MapError(err)
56. 		}
57. 
58. 		baseUrl := os.Getenv("APP_BASE_URL")
59. 		return &viewmodels.CreateUrlResponse{
60. 			Body: webmappers.CreateUrlToResponse(created, baseUrl),
61. 		}, nil
62. 	})
63. 
64. 	huma.Register(api, huma.Operation{
65. 		OperationID: "update-shortened-url",
66. 		Method:      http.MethodPatch,
67. 		Path:        "/user/urls/{id}",
68. 		Summary:     "Update an existing shortened URL",
69. 	}, func(ctx context.Context, input *viewmodels.UpdateUrlInput) (*viewmodels.UpdateUrlResponse, error) {
70. 		claims := GetJWTClaimsFromContext(ctx)
71. 		if claims == nil {
72. 			return nil, huma.NewError(http.StatusUnauthorized, "unauthorized")
73. 		}
74. 
75. 		updated, err := h.UpdateUrl(ctx, input.ID, claims.UserID, input.Body.LongUrl, input.Body.Shortcode, input.Body.ExpiresAt)
76. 		if err != nil {
77. 			return nil, MapError(err)
78. 		}
79. 
80. 		baseUrl := os.Getenv("APP_BASE_URL")
81. 		return &viewmodels.UpdateUrlResponse{
82. 			Body: webmappers.UpdateUrlToResponse(updated, baseUrl),
83. 		}, nil
84. 	})
85. }
86. 
87. // resolvePageSize returns the caller-supplied page size when positive, otherwise
88. // falls back to the DEFAULT_PAGE_SIZE environment variable (default: 20).
89. func resolvePageSize(requested int) int {
90. 	if requested > 0 {
91. 		return requested
92. 	}
93. 	s := os.Getenv("DEFAULT_PAGE_SIZE")
94. 	if s != "" {
95. 		if n, err := strconv.Atoi(s); err == nil && n > 0 {
96. 			return n
97. 		}
98. 	}
99. 	return 20
100. }
